     1→/**
     2→ * MMS API Type Definitions
     3→ *
     4→ * Standard response formats and request types aligned with spec 005.
     5→ *
     6→ * @see specs/005-api.md
     7→ */
     8→
     9→/**
    10→ * Pagination metadata for list responses
    11→ */
    12→export interface PaginationMeta {
    13→  page: number;
    14→  pageSize: number;
    15→  totalItems: number;
    16→  totalPages: number;
    17→  hasNext: boolean;
    18→  hasPrev: boolean;
    19→}
    20→
    21→/**
    22→ * Response timing metadata
    23→ */
    24→export interface TimingMeta {
    25→  durationMs: number;
    26→}
    27→
    28→/**
    29→ * Response metadata
    30→ */
    31→export interface ResponseMeta {
    32→  pagination?: PaginationMeta;
    33→  timing?: TimingMeta;
    34→}
    35→
    36→/**
    37→ * Standard success response
    38→ */
    39→export interface SuccessResponse<T> {
    40→  success: true;
    41→  data: T;
    42→  meta?: ResponseMeta;
    43→}
    44→
    45→/**
    46→ * Error details for error responses
    47→ */
    48→export interface ErrorDetails {
    49→  code: string;
    50→  message: string;
    51→  details?: unknown;
    52→  requestId: string;
    53→}
    54→
    55→/**
    56→ * Standard error response
    57→ */
    58→export interface ErrorResponse {
    59→  success: false;
    60→  error: ErrorDetails;
    61→}
    62→
    63→/**
    64→ * Union type for API responses
    65→ */
    66→export type ApiResponse<T> = SuccessResponse<T> | ErrorResponse;
    67→
    68→/**
    69→ * Create a success response
    70→ */
    71→export function success<T>(data: T, meta?: ResponseMeta): SuccessResponse<T> {
    72→  return {
    73→    success: true,
    74→    data,
    75→    ...(meta && { meta }),
    76→  };
    77→}
    78→
    79→/**
    80→ * Create a paginated success response
    81→ */
    82→export function paginatedSuccess<T>(
    83→  data: T[],
    84→  pagination: {
    85→    page: number;
    86→    pageSize: number;
    87→    totalItems: number;
    88→  },
    89→  timing?: TimingMeta
    90→): SuccessResponse<T[]> {
    91→  const totalPages = Math.ceil(pagination.totalItems / pagination.pageSize);
    92→  return {
    93→    success: true,
    94→    data,
    95→    meta: {
    96→      pagination: {
    97→        page: pagination.page,
    98→        pageSize: pagination.pageSize,
    99→        totalItems: pagination.totalItems,
   100→        totalPages,
   101→        hasNext: pagination.page < totalPages,
   102→        hasPrev: pagination.page > 1,
   103→      },
   104→      ...(timing && { timing }),
   105→    },
   106→  };
   107→}
   108→
   109→/**
   110→ * Create an error response
   111→ */
   112→export function error(
   113→  code: string,
   114→  message: string,
   115→  requestId: string,
   116→  details?: unknown
   117→): ErrorResponse {
   118→  return {
   119→    success: false,
   120→    error: {
   121→      code,
   122→      message,
   123→      requestId,
   124→      ...(details !== undefined && { details }),
   125→    },
   126→  };
   127→}
   128→
   129→/**
   130→ * Standard error codes used across the API
   131→ */
   132→export const ErrorCodes = {
   133→  // Client errors (4xx)
   134→  VALIDATION_ERROR: 'VALIDATION_ERROR',
   135→  NOT_FOUND: 'NOT_FOUND',
   136→  UNAUTHORIZED: 'UNAUTHORIZED',
   137→  FORBIDDEN: 'FORBIDDEN',
   138→  CONFLICT: 'CONFLICT',
   139→  RATE_LIMITED: 'RATE_LIMITED',
   140→
   141→  // Business logic errors
   142→  MAXIMO_LOCK: 'MAXIMO_LOCK',
   143→  BASELINE_LOCK: 'BASELINE_LOCK',
   144→  OUTSIDE_WINDOW: 'OUTSIDE_WINDOW',
   145→  TRACK_CONFLICT: 'TRACK_CONFLICT',
   146→  MATERIAL_BLOCK: 'MATERIAL_BLOCK',
   147→  SERVICE_DEMAND_VIOLATION: 'SERVICE_DEMAND_VIOLATION',
   148→
   149→  // Server errors (5xx)
