/**
 * MMS API Type Definitions
 *
 * Standard response formats and request types aligned with spec 005.
 *
 * @see specs/005-api.md
 */

/**
 * Pagination metadata for list responses
 */
export interface PaginationMeta {
  page: number;
  pageSize: number;
  totalItems: number;
  totalPages: number;
  hasNext: boolean;
  hasPrev: boolean;
}

/**
 * Response timing metadata
 */
export interface TimingMeta {
  durationMs: number;
}

/**
 * Response metadata
 */
export interface ResponseMeta {
  pagination?: PaginationMeta;
  timing?: TimingMeta;
}

/**
 * Standard success response
 */
export interface SuccessResponse<T> {
  success: true;
  data: T;
  meta?: ResponseMeta;
}

/**
 * Error details for error responses
 */
export interface ErrorDetails {
  code: string;
  message: string;
  details?: unknown;
  requestId: string;
}

/**
 * Standard error response
 */
export interface ErrorResponse {
  success: false;
  error: ErrorDetails;
}

/**
 * Union type for API responses
 */
export type ApiResponse<T> = SuccessResponse<T> | ErrorResponse;

/**
 * Create a success response
 */
export function success<T>(data: T, meta?: ResponseMeta): SuccessResponse<T> {
  return {
    success: true,
    data,
    ...(meta && { meta }),
  };
}

/**
 * Create a paginated success response
 */
export function paginatedSuccess<T>(
  data: T[],
  pagination: {
    page: number;
    pageSize: number;
    totalItems: number;
  },
  timing?: TimingMeta
): SuccessResponse<T[]> {
  const totalPages = Math.ceil(pagination.totalItems / pagination.pageSize);
  return {
    success: true,
    data,
    meta: {
      pagination: {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems: pagination.totalItems,
        totalPages,
        hasNext: pagination.page < totalPages,
        hasPrev: pagination.page > 1,
      },
      ...(timing && { timing }),
    },
  };
}

/**
 * Create an error response
 */
export function error(
  code: string,
  message: string,
  requestId: string,
  details?: unknown
): ErrorResponse {
  return {
    success: false,
    error: {
      code,
      message,
      requestId,
      ...(details !== undefined && { details }),
    },
  };
}

/**
 * Standard error codes used across the API
 */
export const ErrorCodes = {
  // Client errors (4xx)
  VALIDATION_ERROR: 'VALIDATION_ERROR',
  NOT_FOUND: 'NOT_FOUND',
  UNAUTHORIZED: 'UNAUTHORIZED',
  FORBIDDEN: 'FORBIDDEN',
  CONFLICT: 'CONFLICT',
  RATE_LIMITED: 'RATE_LIMITED',

  // Business logic errors
  MAXIMO_LOCK: 'MAXIMO_LOCK',
  BASELINE_LOCK: 'BASELINE_LOCK',
  OUTSIDE_WINDOW: 'OUTSIDE_WINDOW',
  TRACK_CONFLICT: 'TRACK_CONFLICT',
  MATERIAL_BLOCK: 'MATERIAL_BLOCK',
  SERVICE_DEMAND_VIOLATION: 'SERVICE_DEMAND_VIOLATION',

  // Server errors (5xx)
  INTERNAL_ERROR: 'INTERNAL_ERROR',
  SERVICE_UNAVAILABLE: 'SERVICE_UNAVAILABLE',
  DATABASE_ERROR: 'DATABASE_ERROR',
  EXTERNAL_SERVICE_ERROR: 'EXTERNAL_SERVICE_ERROR',
} as const;

export type ErrorCode = (typeof ErrorCodes)[keyof typeof ErrorCodes];

/**
 * Standard query parameters for list endpoints
 */
export interface ListQueryParams {
  page?: number;
  pageSize?: number;
  sort?: string;
  filter?: string;
  fields?: string;
}

/**
 * Parsed pagination parameters with defaults applied
 */
export interface ParsedPagination {
  page: number;
  pageSize: number;
  offset: number;
  sort?: { field: string; direction: 'asc' | 'desc' };
}

/**
 * Parse pagination query parameters with defaults
 */
export function parsePaginationQuery(params: ListQueryParams): ParsedPagination {
  const page = Math.max(1, Number(params.page) || 1);
  const pageSize = Math.min(200, Math.max(1, Number(params.pageSize) || 50));
  const offset = (page - 1) * pageSize;

  let sort: { field: string; direction: 'asc' | 'desc' } | undefined;
  if (params.sort) {
    const [field, dir] = params.sort.split(':');
    sort = {
      field,
      direction: dir === 'desc' ? 'desc' : 'asc',
    };
  }

  return { page, pageSize, offset, sort };
}

/**
 * JWT token payload structure
 */
export interface JwtPayload {
  sub: string;
  email: string;
  roles: string[];
  depotId?: string;
  iat: number;
  exp: number;
}

/**
 * Authenticated user context (attached to request)
 */
export interface AuthUser {
  id: string;
  email: string;
  roles: string[];
  depotId?: string;
}

/**
 * Extended Hono context variables
 */
export interface AppVariables {
  requestId: string;
  startTime: number;
  user?: AuthUser;
}

