      window.ui = SwaggerUIBundle({
        url: "${specUrl}",
        dom_id: '#swagger-ui',
        deepLinking: true,
        presets: [
          SwaggerUIBundle.presets.apis,
          SwaggerUIStandalonePreset
        ],
        plugins: [
          SwaggerUIBundle.plugins.DownloadUrl
        ],
        layout: "StandaloneLayout",
        defaultModelsExpandDepth: 1,
        defaultModelExpandDepth: 1,
        docExpansion: "list",
        filter: true,
        showExtensions: true,
        showCommonExtensions: true,
        tryItOutEnabled: true
      });
    };
  </script>
</body>
</html>`;
}

/**
 * Create OpenAPI routes for Hono
 */
export function createOpenApiRoutes(app: { get: (path: string, handler: (c: Context) => Response | Promise<Response>) => void }) {
  // Serve OpenAPI spec as JSON
  app.get('/openapi.json', (c: Context) => {
    return c.json(openApiSpec);
  });

  // Serve Swagger UI
  app.get('/docs', (c: Context) => {
    const html = getSwaggerHtml('/api/v1/openapi.json');
    return c.html(html);
  });
}

