     2→ * Rate Limiter Middleware
     3→ *
     4→ * Implements rate limiting using Redis sliding window counter algorithm.
     5→ * Protects the API from abuse with configurable limits per user/IP.
     6→ *
     7→ * @see specs/005-api.md - Rate Limiting: 100 requests/minute per user
     8→ */
     9→
    10→import type { Context, Next, MiddlewareHandler } from 'hono';
    11→import type { AppVariables } from '../types';
    12→import { getRedisClient } from '../../lib/redis/connection';
    13→import { logger } from '../../lib/logging/logger';
    14→import { rateLimitMetrics } from '../../lib/metrics';
    15→
    16→/**
    17→ * Rate limiter configuration
    18→ */
    19→export interface RateLimitConfig {
    20→  /** Maximum requests allowed per window */
    21→  limit: number;
    22→  /** Window duration in seconds */
    23→  windowSeconds: number;
    24→  /** Custom key generator function */
    25→  keyGenerator?: (c: Context<{ Variables: AppVariables }>) => string;
    26→  /** Skip rate limiting for certain requests */
    27→  skip?: (c: Context<{ Variables: AppVariables }>) => boolean;
    28→  /** Redis key prefix */
