    30→}
    31→
    32→/**
    33→ * Default rate limit configuration
    34→ * 100 requests per minute per user (per spec 005)
    35→ */
    36→const DEFAULT_CONFIG: RateLimitConfig = {
    37→  limit: 100,
    38→  windowSeconds: 60,
    39→  keyPrefix: 'ratelimit:',
    40→};
    41→
    42→/**
    43→ * Rate limit info added to response headers
    44→ */
    45→export interface RateLimitInfo {
    46→  limit: number;
    47→  remaining: number;
    48→  reset: number;
    49→}
    50→
    51→/**
    52→ * Get rate limit identifier for a request
    53→ * Uses user ID if authenticated, otherwise uses IP address
    54→ */
