/**
 * Rate Limiter Middleware
 *
 * Implements rate limiting using Redis sliding window counter algorithm.
 * Protects the API from abuse with configurable limits per user/IP.
 *
 * @see specs/005-api.md - Rate Limiting: 100 requests/minute per user
 */

import type { Context, Next, MiddlewareHandler } from 'hono';
import type { AppVariables } from '../types';
import { getRedisClient } from '../../lib/redis/connection';
import { logger } from '../../lib/logging/logger';
import { rateLimitMetrics } from '../../lib/metrics';

/**
 * Rate limiter configuration
 */
export interface RateLimitConfig {
  /** Maximum requests allowed per window */
  limit: number;
  /** Window duration in seconds */
  windowSeconds: number;
  /** Custom key generator function */
  keyGenerator?: (c: Context<{ Variables: AppVariables }>) => string;
  /** Skip rate limiting for certain requests */
  skip?: (c: Context<{ Variables: AppVariables }>) => boolean;
  /** Redis key prefix */
  keyPrefix?: string;
}

/**
 * Default rate limit configuration
 * 100 requests per minute per user (per spec 005)
 */
const DEFAULT_CONFIG: RateLimitConfig = {
  limit: 100,
  windowSeconds: 60,
  keyPrefix: 'ratelimit:',
};

/**
 * Rate limit info added to response headers
 */
export interface RateLimitInfo {
  limit: number;
  remaining: number;
  reset: number;
}

/**
 * Get rate limit identifier for a request
 * Uses user ID if authenticated, otherwise uses IP address
 */
function getDefaultKey(c: Context<{ Variables: AppVariables }>): string {
  const user = c.get('user');
  if (user?.id) {
    return `user:${user.id}`;
  }

  // Fallback to IP address for unauthenticated requests
  const forwarded = c.req.header('x-forwarded-for');
  const ip = forwarded?.split(',')[0]?.trim() || 'unknown';
  return `ip:${ip}`;
}

/**
 * Calculate reset timestamp (end of current window)
 */
function getResetTimestamp(windowSeconds: number): number {
  const windowStart = Math.floor(Date.now() / 1000 / windowSeconds) * windowSeconds;
  return windowStart + windowSeconds;
}

/**
 * Check rate limit and update counter using Redis
 *
 * Uses a sliding window approach with two adjacent windows
 * for smoother rate limiting near window boundaries.
 */
async function checkRateLimit(
  key: string,
  limit: number,
  windowSeconds: number
): Promise<{ allowed: boolean; remaining: number; reset: number }> {
  const redis = getRedisClient();
  const now = Date.now() / 1000;
  const windowStart = Math.floor(now / windowSeconds) * windowSeconds;
  const currentWindowKey = `${key}:${windowStart}`;
  const previousWindowKey = `${key}:${windowStart - windowSeconds}`;

  try {
    // Get current and previous window counts
    const pipeline = redis.pipeline();
    pipeline.get(currentWindowKey);
    pipeline.get(previousWindowKey);
    pipeline.incr(currentWindowKey);
    pipeline.expire(currentWindowKey, windowSeconds * 2);

    const results = await pipeline.exec();
    if (!results) {
      // Redis error, allow request but log
      logger.warn({ key }, 'Rate limiter Redis pipeline failed');
      return { allowed: true, remaining: limit, reset: getResetTimestamp(windowSeconds) };
    }

    const currentCount = parseInt(String(results[0]?.[1] || '0'), 10);
    const previousCount = parseInt(String(results[1]?.[1] || '0'), 10);

    // Calculate weighted count using sliding window
    const elapsedInWindow = now - windowStart;
    const previousWeight = 1 - (elapsedInWindow / windowSeconds);
    const weightedCount = currentCount + Math.floor(previousCount * previousWeight);

    const remaining = Math.max(0, limit - weightedCount - 1);
    const reset = getResetTimestamp(windowSeconds);

    if (weightedCount >= limit) {
      // Decrement the counter we just incremented since we're rejecting
      await redis.decr(currentWindowKey);
      return { allowed: false, remaining: 0, reset };
    }

    return { allowed: true, remaining, reset };
  } catch (error) {
    // On Redis error, allow the request but log the error
    logger.error({ key, error }, 'Rate limiter Redis error');
    return { allowed: true, remaining: limit, reset: getResetTimestamp(windowSeconds) };
  }
}

/**
 * Add rate limit headers to response
 */
function addRateLimitHeaders(
  c: Context,
  info: RateLimitInfo
): void {
  c.header('X-RateLimit-Limit', String(info.limit));
  c.header('X-RateLimit-Remaining', String(info.remaining));
  c.header('X-RateLimit-Reset', String(info.reset));
}

/**
 * Create rate limiter middleware
 *
 * @example
 * // Use default config (100 requests/minute)
 * app.use('*', rateLimiter());
 *
 * @example
 * // Custom config
 * app.use('*', rateLimiter({ limit: 50, windowSeconds: 30 }));
 *
 * @example
 * // Skip rate limiting for health checks
 * app.use('*', rateLimiter({
 *   skip: (c) => c.req.path === '/health'
 * }));
 */
export function rateLimiter(
  config: Partial<RateLimitConfig> = {}
): MiddlewareHandler<{ Variables: AppVariables }> {
  const mergedConfig: RateLimitConfig = {
    ...DEFAULT_CONFIG,
    ...config,
  };

  const { limit, windowSeconds, keyGenerator, skip, keyPrefix } = mergedConfig;

  return async (c: Context<{ Variables: AppVariables }>, next: Next) => {
    // Check if rate limiting should be skipped
    if (skip?.(c)) {
      return next();
    }

    // Generate rate limit key
    const identifier = keyGenerator?.(c) || getDefaultKey(c);
    const key = `${keyPrefix}${identifier}`;

    // Check rate limit
    const { allowed, remaining, reset } = await checkRateLimit(key, limit, windowSeconds);

    // Add rate limit headers to all responses
    addRateLimitHeaders(c, { limit, remaining, reset });

    if (!allowed) {
      // Record rate limit hit in metrics
      rateLimitMetrics.rateLimitExceeded.inc({
        identifier_type: identifier.startsWith('user:') ? 'user' : 'ip',
      });

      logger.warn(
        {
          key,
          limit,
          windowSeconds,
          path: c.req.path,
          method: c.req.method,
        },
        'Rate limit exceeded'
      );

      // Return 429 with JSON error response
      const requestId = c.get('requestId') || 'unknown';
      return c.json(
        {
          success: false,
          error: {
            code: 'RATE_LIMITED',
            message: `Rate limit exceeded: ${limit} requests per ${windowSeconds} seconds`,
            requestId,
            details: {
              limit,
              windowSeconds,
              resetAt: new Date(reset * 1000).toISOString(),
            },
          },
        },
        429
      );
    }

    // Record successful rate limit check in metrics
    rateLimitMetrics.rateLimitChecks.inc({
      identifier_type: identifier.startsWith('user:') ? 'user' : 'ip',
      result: 'allowed',
    });

    return next();
  };
}

/**
 * Create a stricter rate limiter for sensitive endpoints
 * (e.g., authentication endpoints)
 */
export function strictRateLimiter(): MiddlewareHandler<{ Variables: AppVariables }> {
  return rateLimiter({
    limit: 10,
    windowSeconds: 60,
    keyPrefix: 'ratelimit:strict:',
  });
}

/**
 * Create a lenient rate limiter for read-only endpoints
 */
export function lenientRateLimiter(): MiddlewareHandler<{ Variables: AppVariables }> {
  return rateLimiter({
    limit: 200,
    windowSeconds: 60,
    keyPrefix: 'ratelimit:lenient:',
  });
}

