/**
 * Request Context Middleware
 *
 * Provides request ID generation and timing for all API requests.
 * Essential for distributed tracing and debugging.
 */

import type { Context, Next, MiddlewareHandler } from 'hono';
import { v4 as uuidv4 } from 'uuid';
import type { AppVariables } from '../types';

/**
 * Request context middleware
 *
 * - Generates unique request ID (or uses X-Request-ID header)
 * - Records request start time for duration calculation
 * - Adds X-Request-ID header to response
 */
export function requestContext(): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next) => {
    const requestId = c.req.header('X-Request-ID') || uuidv4();
    const startTime = performance.now();

    c.set('requestId', requestId);
    c.set('startTime', startTime);

    c.header('X-Request-ID', requestId);

    await next();
  };
}

/**
 * Get request duration in milliseconds
 */
export function getRequestDuration(c: Context<{ Variables: AppVariables }>): number {
  const startTime = c.get('startTime');
  return Math.round(performance.now() - startTime);
}

/**
 * Get request ID from context
 */
export function getRequestId(c: Context<{ Variables: AppVariables }>): string {
  return c.get('requestId');
}

