     1→/**
     2→ * MMS WebSocket Hub
     3→ *
     4→ * Manages WebSocket connections for real-time canvas updates, optimizer progress,
     5→ * and collaborative editing. Implements:
     6→ * - Connection management with JWT authentication
     7→ * - Region-based canvas subscriptions
     8→ * - Event broadcasting with room support
     9→ * - PM move via WebSocket with validation
    10→ * - Optimizer progress streaming
    11→ *
    12→ * Security:
    13→ * - All connections must authenticate within 10 seconds
    14→ * - Unauthenticated connections are automatically closed
    15→ * - All events are only sent to authorized users
    16→ *
    17→ * @see specs/005-api.md Section 5.14 (WebSocket Events)
    18→ */
    19→
    20→import type { ServerWebSocket } from 'bun';
    21→import { randomUUID } from 'crypto';
    22→import { logger } from '../../lib/logging/logger';
    23→import { getAuthService, type SessionData } from '../../services/auth';
    24→import type {
    25→  ClientConnection,
    26→  CanvasSubscriptionRegion,
    27→  ClientMessage,
    28→  ServerMessage,
    29→  PmUpdatedData,
    30→  PmLockedData,
    31→  ManhourUpdatedData,
    32→  DriftUpdatedData,
    33→  OptimizerProgressData,
    34→  OptimizerCompleteData,
    35→  Room,
    36→} from './types';
    37→
    38→// =============================================================================
    39→// Constants
    40→// =============================================================================
    41→
    42→const AUTH_TIMEOUT_MS = 10_000;
    43→const PING_INTERVAL_MS = 30_000;
    44→const MAX_SUBSCRIPTIONS_PER_CLIENT = 10;
    45→
    46→// =============================================================================
    47→// WebSocket Hub
    48→// =============================================================================
    49→
    50→/**
    51→ * Auth service interface for dependency injection
    52→ */
    53→export interface AuthServiceLike {
    54→  verifyAccessToken(token: string): Promise<SessionData>;
    55→}
    56→
    57→/**
    58→ * WebSocket Hub for real-time communication
    59→ */
    60→export class WebSocketHub {
    61→  /** Active client connections by connection ID */
    62→  private connections = new Map<string, ClientConnection>();
    63→
    64→  /** WebSocket instances by connection ID */
    65→  private sockets = new Map<string, ServerWebSocket<WebSocketData>>();
    66→
    67→  /** Rooms for broadcasting */
    68→  private rooms = new Map<string, Room>();
    69→
    70→  /** User ID to connection IDs mapping (one user can have multiple connections) */
    71→  private userConnections = new Map<string, Set<string>>();
    72→
    73→  /** Auth timeout handles */
    74→  private authTimeouts = new Map<string, ReturnType<typeof setTimeout>>();
    75→
    76→  /** Ping interval handle */
    77→  private pingInterval?: ReturnType<typeof setInterval>;
    78→
    79→  private log = logger.child({ service: 'websocket-hub' });
    80→
    81→  /** Auth service getter - allows injection for testing */
    82→  private authServiceGetter: () => AuthServiceLike;
    83→
    84→  constructor(authServiceGetter?: () => AuthServiceLike) {
    85→    this.authServiceGetter = authServiceGetter ?? getAuthService;
    86→    // Create default rooms
    87→    this.createRoom('canvas', 'canvas');
    88→    this.createRoom('optimizer', 'optimizer');
    89→  }
    90→
    91→  /**
    92→   * Start the hub (start ping interval)
    93→   */
    94→  start(): void {
    95→    this.pingInterval = setInterval(() => this.broadcastPing(), PING_INTERVAL_MS);
    96→    this.log.info('WebSocket hub started');
    97→  }
    98→
    99→  /**
   100→   * Stop the hub (cleanup)
   101→   */
   102→  stop(): void {
   103→    if (this.pingInterval) {
   104→      clearInterval(this.pingInterval);
   105→    }
   106→
   107→    // Close all connections
   108→    for (const [connectionId] of this.connections) {
   109→      this.disconnect(connectionId, 'Server shutting down');
   110→    }
   111→
   112→    this.log.info('WebSocket hub stopped');
   113→  }
   114→
   115→  /**
   116→   * Handle new WebSocket connection
   117→   */
   118→  onOpen(ws: ServerWebSocket<WebSocketData>): void {
   119→    const connectionId = ws.data.connectionId;
   120→
   121→    const connection: ClientConnection = {
   122→      id: connectionId,
   123→      state: 'authenticating',
   124→      subscriptions: new Map(),
   125→      connectedAt: new Date(),
   126→      lastActivityAt: new Date(),
   127→      ipAddress: ws.data.ipAddress,
   128→      userAgent: ws.data.userAgent,
   129→    };
   130→
   131→    this.connections.set(connectionId, connection);
   132→    this.sockets.set(connectionId, ws);
   133→
   134→    // Set auth timeout - client must authenticate within timeout period
   135→    const timeoutHandle = setTimeout(() => {
   136→      const conn = this.connections.get(connectionId);
   137→      if (conn && conn.state !== 'authenticated') {
   138→        this.log.warn({ connectionId }, 'Connection auth timeout - closing');
   139→        this.disconnect(connectionId, 'Authentication timeout');
   140→      }
   141→    }, AUTH_TIMEOUT_MS);
   142→
   143→    this.authTimeouts.set(connectionId, timeoutHandle);
   144→
   145→    this.log.debug({ connectionId, ipAddress: ws.data.ipAddress }, 'WebSocket connection opened');
   146→  }
   147→
   148→  /**
   149→   * Handle WebSocket message
   150→   */
   151→  async onMessage(ws: ServerWebSocket<WebSocketData>, message: string | Buffer): Promise<void> {
   152→    const connectionId = ws.data.connectionId;
   153→    const connection = this.connections.get(connectionId);
   154→
   155→    if (!connection) {
   156→      ws.close(4001, 'Connection not found');
   157→      return;
   158→    }
   159→
   160→    connection.lastActivityAt = new Date();
   161→
   162→    try {
   163→      const data = typeof message === 'string' ? message : message.toString('utf-8');
   164→      const msg = JSON.parse(data) as ClientMessage;
   165→
   166→      await this.handleMessage(connectionId, msg);
   167→    } catch (error) {
   168→      this.log.error({ connectionId, error }, 'Error parsing WebSocket message');
   169→      this.sendError(connectionId, 'PARSE_ERROR', 'Invalid message format');
   170→    }
   171→  }
   172→
   173→  /**
   174→   * Handle WebSocket close
   175→   */
   176→  onClose(ws: ServerWebSocket<WebSocketData>, code: number, reason: string): void {
   177→    const connectionId = ws.data.connectionId;
   178→    this.cleanup(connectionId);
   179→    this.log.debug({ connectionId, code, reason }, 'WebSocket connection closed');
   180→  }
   181→
   182→  /**
   183→   * Handle WebSocket error
   184→   */
   185→  onError(ws: ServerWebSocket<WebSocketData>, error: Error): void {
   186→    const connectionId = ws.data.connectionId;
   187→    this.log.error({ connectionId, error: error.message }, 'WebSocket error');
   188→    this.cleanup(connectionId);
   189→  }
   190→
   191→  // ===========================================================================
   192→  // Message Handlers
   193→  // ===========================================================================
   194→
   195→  private async handleMessage(connectionId: string, msg: ClientMessage): Promise<void> {
   196→    const connection = this.connections.get(connectionId);
   197→    if (!connection) return;
   198→
   199→    switch (msg.type) {
   200→      case 'AUTH':
   201→        await this.handleAuth(connectionId, msg.data.token);
   202→        break;
   203→
   204→      case 'canvas:subscribe':
   205→        this.handleSubscribe(connectionId, msg.data);
   206→        break;
   207→
   208→      case 'canvas:unsubscribe':
   209→        this.handleUnsubscribe(connectionId, msg.data.subscriptionId);
   210→        break;
   211→
   212→      case 'canvas:move_pm':
   213→        await this.handleMovePm(connectionId, msg.data);
   214→        break;
   215→
   216→      case 'ping':
   217→        this.send(connectionId, { type: 'pong' });
   218→        break;
   219→
   220→      default:
   221→        this.sendError(connectionId, 'UNKNOWN_MESSAGE', `Unknown message type: ${(msg as { type: string }).type}`);
   222→    }
   223→  }
   224→
   225→  /**
   226→   * Handle authentication request
   227→   */
   228→  private async handleAuth(connectionId: string, token: string): Promise<void> {
   229→    const connection = this.connections.get(connectionId);
   230→    if (!connection) return;
   231→
   232→    try {
   233→      const authService = this.authServiceGetter();
   234→      const session: SessionData = await authService.verifyAccessToken(token);
   235→
   236→      // Clear auth timeout
   237→      const timeoutHandle = this.authTimeouts.get(connectionId);
   238→      if (timeoutHandle) {
   239→        clearTimeout(timeoutHandle);
   240→        this.authTimeouts.delete(connectionId);
   241→      }
   242→
   243→      // Update connection state
   244→      connection.userId = session.userId;
   245→      connection.displayName = session.email;
   246→      connection.roles = session.roles;
   247→      connection.depotId = session.depotId ?? undefined;
   248→      connection.state = 'authenticated';
   249→
   250→      // Track user connection
   251→      let userConns = this.userConnections.get(session.userId);
   252→      if (!userConns) {
   253→        userConns = new Set();
   254→        this.userConnections.set(session.userId, userConns);
   255→      }
   256→      userConns.add(connectionId);
   257→
   258→      // Join default rooms (canvas for PM/manhour/drift updates, optimizer for job progress)
   259→      this.joinRoom(connectionId, 'canvas');
   260→      this.joinRoom(connectionId, 'optimizer');
   261→
   262→      // Send success response
   263→      this.send(connectionId, {
   264→        type: 'AUTH_RESULT',
   265→        data: {
   266→          success: true,
   267→          userId: session.userId,
   268→          displayName: session.email,
   269→        },
   270→      });
   271→
   272→      this.log.info({ connectionId, userId: session.userId }, 'WebSocket authenticated');
   273→    } catch (error) {
   274→      const message = error instanceof Error ? error.message : 'Authentication failed';
   275→      this.send(connectionId, {
   276→        type: 'AUTH_RESULT',
   277→        data: { success: false, error: message },
   278→      });
   279→
   280→      // Close connection after failed auth
   281→      this.disconnect(connectionId, 'Authentication failed');
   282→    }
   283→  }
   284→
   285→  /**
   286→   * Handle canvas subscription request
   287→   */
   288→  private handleSubscribe(connectionId: string, region: CanvasSubscriptionRegion): void {
   289→    const connection = this.connections.get(connectionId);
   290→    if (!connection || connection.state !== 'authenticated') {
   291→      this.sendError(connectionId, 'UNAUTHORIZED', 'Must be authenticated to subscribe');
   292→      return;
   293→    }
   294→
   295→    if (connection.subscriptions.size >= MAX_SUBSCRIPTIONS_PER_CLIENT) {
   296→      this.sendError(connectionId, 'MAX_SUBSCRIPTIONS', `Maximum ${MAX_SUBSCRIPTIONS_PER_CLIENT} subscriptions allowed`);
   297→      return;
   298→    }
   299→
   300→    const subscriptionId = randomUUID();
   301→    connection.subscriptions.set(subscriptionId, region);
   302→
   303→    // Create room for this subscription if it doesn't exist
   304→    const roomId = this.getCanvasRoomId(region);
   305→    if (!this.rooms.has(roomId)) {
   306→      this.createRoom(roomId, 'canvas', { region });
   307→    }
   308→    this.joinRoom(connectionId, roomId);
   309→
   310→    // Count trains in region (simplified - would query DB in production)
   311→    const trainCount = region.trainIds?.length ?? 0;
   312→
   313→    this.send(connectionId, {
   314→      type: 'canvas:subscription_confirmed',
   315→      data: {
   316→        subscriptionId,
   317→        region,
   318→        trainCount,
   319→      },
   320→    });
   321→
   322→    this.log.debug({ connectionId, subscriptionId, region }, 'Canvas subscription created');
   323→  }
   324→
   325→  /**
   326→   * Handle canvas unsubscription request
   327→   */
   328→  private handleUnsubscribe(connectionId: string, subscriptionId: string): void {
   329→    const connection = this.connections.get(connectionId);
   330→    if (!connection) return;
   331→
   332→    const region = connection.subscriptions.get(subscriptionId);
   333→    if (region) {
   334→      connection.subscriptions.delete(subscriptionId);
   335→
   336→      // Leave the room if this was the only subscription
   337→      const roomId = this.getCanvasRoomId(region);
   338→      this.leaveRoom(connectionId, roomId);
   339→    }
   340→  }
   341→
   342→  /**
   343→   * Handle PM move request via WebSocket
   344→   *
   345→   * CRITICAL: Validates against Maximo status lock to prevent race conditions
   346→   * with in-progress work orders.
   347→   */
   348→  private async handleMovePm(connectionId: string, data: { pmId: string; newTargetDate: string; newTrackId?: string }): Promise<void> {
   349→    const connection = this.connections.get(connectionId);
   350→    if (!connection || connection.state !== 'authenticated') {
   351→      this.send(connectionId, {
   352→        type: 'canvas:move_pm_result',
   353→        data: {
   354→          success: false,
   355→          pmId: data.pmId,
   356→          error: { code: 'UNAUTHORIZED', message: 'Must be authenticated' },
   357→        },
   358→      });
   359→      return;
   360→    }
   361→
   362→    try {
   363→      // Dynamic import to avoid circular dependency
   364→      const { getPMSchedulerService } = await import('../../services/pm-scheduler');
   365→      const pmService = getPMSchedulerService();
   366→
   367→      // Get current PM state for validation and broadcasting
   368→      const pm = await pmService.getPm(data.pmId);
   369→      const previousDate = pm.targetDate;
   370→
   371→      // Move the PM (validation happens in the service)
   372→      await pmService.movePm({
   373→        pmScheduleId: data.pmId,
   374→        newTargetDate: data.newTargetDate,
   375→        newTrackId: data.newTrackId,
   376→        reason: 'Moved via drag-and-drop on canvas',
   377→        movedBy: connection.userId!,
   378→      });
   379→
   380→      // Send success to requestor
   381→      this.send(connectionId, {
   382→        type: 'canvas:move_pm_result',
   383→        data: {
   384→          success: true,
   385→          pmId: data.pmId,
   386→          newTargetDate: data.newTargetDate,
   387→          newTrackId: data.newTrackId,
   388→        },
   389→      });
   390→
   391→      // Broadcast to all canvas subscribers
   392→      this.broadcastPmUpdated({
   393→        pmId: data.pmId,
   394→        trainId: pm.trainId,
   395→        trainNumber: pm.train?.trainNumber ?? 'Unknown',
   396→        changes: [
   397→          { field: 'targetDate', oldValue: previousDate, newValue: data.newTargetDate },
   398→          ...(data.newTrackId ? [{ field: 'assignedTrackId', oldValue: pm.assignedTrackId, newValue: data.newTrackId }] : []),
   399→        ],
   400→        changedBy: {
   401→          userId: connection.userId!,
   402→          displayName: connection.displayName ?? 'Unknown',
   403→        },
   404→      });
   405→
   406→      this.log.info({ connectionId, pmId: data.pmId, newTargetDate: data.newTargetDate }, 'PM moved via WebSocket');
   407→    } catch (error) {
   408→      // Map specific error types to WebSocket error codes
   409→      let errorCode: 'MAXIMO_LOCK' | 'OUTSIDE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL_BLOCK' | 'BASELINE_LOCK' | 'NOT_FOUND' | 'INTERNAL_ERROR' = 'INTERNAL_ERROR';
   410→      let suggestion: string | undefined;
   411→      let maximoStatus: string | undefined;
   412→
   413→      if (error instanceof Error) {
   414→        const errorName = error.constructor.name;
   415→
   416→        if (errorName === 'MaximoLockError') {
   417→          errorCode = 'MAXIMO_LOCK';
   418→          suggestion = 'Wait for work order completion or update in Maximo';
   419→          maximoStatus = 'INPRG';
   420→        } else if (errorName === 'ComplianceWindowError') {
   421→          errorCode = 'OUTSIDE_WINDOW';
   422→          suggestion = 'Drag within the highlighted compliance window';
   423→        } else if (errorName === 'TrackConflictError') {
   424→          errorCode = 'TRACK_CONFLICT';
   425→          suggestion = 'Select a different track or date';
   426→        } else if (errorName === 'PmScheduleNotFoundError') {
   427→          errorCode = 'NOT_FOUND';
   428→        } else if (errorName === 'BusinessRuleError' && error.message.includes('locked')) {
   429→          errorCode = 'BASELINE_LOCK';
   430→          suggestion = 'Unlock the PM first or contact the user who locked it';
   431→        }
   432→      }
   433→
   434→      const message = error instanceof Error ? error.message : 'Failed to move PM';
   435→      this.send(connectionId, {
   436→        type: 'canvas:move_pm_result',
   437→        data: {
   438→          success: false,
   439→          pmId: data.pmId,
   440→          error: { code: errorCode, message, suggestion, maximoStatus },
   441→        },
   442→      });
   443→      this.log.error({ connectionId, pmId: data.pmId, error }, 'PM move failed');
   444→    }
   445→  }
   446→
   447→  // ===========================================================================
   448→  // Broadcasting Methods
   449→  // ===========================================================================
   450→
   451→  /**
   452→   * Broadcast PM updated event to all canvas subscribers
   453→   */
   454→  broadcastPmUpdated(data: PmUpdatedData): void {
   455→    this.broadcastToRoom('canvas', {
   456→      type: 'canvas:pm_updated',
   457→      data,
   458→      timestamp: new Date().toISOString(),
   459→    });
   460→  }
   461→
   462→  /**
   463→   * Broadcast PM lock/unlock event
   464→   */
   465→  broadcastPmLocked(data: PmLockedData): void {
   466→    this.broadcastToRoom('canvas', {
   467→      type: 'canvas:pm_locked',
   468→      data,
   469→      timestamp: new Date().toISOString(),
   470→    });
   471→  }
   472→
   473→  /**
   474→   * Broadcast man-hour updated event
   475→   */
   476→  broadcastManhourUpdated(data: ManhourUpdatedData): void {
   477→    this.broadcastToRoom('canvas', {
   478→      type: 'canvas:manhour_updated',
   479→      data,
   480→      timestamp: new Date().toISOString(),
   481→    });
   482→  }
   483→
   484→  /**
   485→   * Broadcast drift analysis updated event
   486→   */
   487→  broadcastDriftUpdated(data: DriftUpdatedData): void {
   488→    this.broadcastToRoom('canvas', {
   489→      type: 'canvas:drift_updated',
   490→      data,
   491→      timestamp: new Date().toISOString(),
   492→    });
   493→  }
   494→
   495→  /**
   496→   * Broadcast optimizer progress to optimizer room
   497→   */
   498→  broadcastOptimizerProgress(data: OptimizerProgressData): void {
   499→    this.broadcastToRoom('optimizer', {
   500→      type: 'optimizer:progress',
   501→      data,
   502→      timestamp: new Date().toISOString(),
   503→    });
   504→  }
   505→
   506→  /**
   507→   * Broadcast optimizer complete to optimizer room
   508→   */
   509→  broadcastOptimizerComplete(data: OptimizerCompleteData): void {
   510→    this.broadcastToRoom('optimizer', {
   511→      type: 'optimizer:complete',
   512→      data,
   513→      timestamp: new Date().toISOString(),
   514→    });
   515→  }
   516→
   517→  /**
   518→   * Broadcast to a specific user (all their connections)
   519→   */
   520→  broadcastToUser(userId: string, message: ServerMessage): void {
   521→    const connectionIds = this.userConnections.get(userId);
   522→    if (connectionIds) {
   523→      for (const connectionId of connectionIds) {
   524→        this.send(connectionId, message);
   525→      }
   526→    }
   527→  }
   528→
   529→  // ===========================================================================
   530→  // Room Management
   531→  // ===========================================================================
   532→
   533→  private createRoom(roomId: string, type: Room['type'], metadata?: Record<string, unknown>): void {
   534→    if (!this.rooms.has(roomId)) {
   535→      this.rooms.set(roomId, {
   536→        id: roomId,
   537→        type,
   538→        clients: new Set(),
   539→        metadata,
   540→      });
   541→    }
   542→  }
   543→
   544→  private joinRoom(connectionId: string, roomId: string): void {
   545→    const room = this.rooms.get(roomId);
   546→    if (room) {
   547→      room.clients.add(connectionId);
   548→    }
   549→  }
   550→
   551→  private leaveRoom(connectionId: string, roomId: string): void {
   552→    const room = this.rooms.get(roomId);
   553→    if (room) {
   554→      room.clients.delete(connectionId);
   555→    }
   556→  }
   557→
   558→  private broadcastToRoom(roomId: string, message: ServerMessage): void {
   559→    const room = this.rooms.get(roomId);
   560→    if (!room) return;
   561→
   562→    for (const connectionId of room.clients) {
   563→      this.send(connectionId, message);
   564→    }
   565→  }
   566→
   567→  private getCanvasRoomId(region: CanvasSubscriptionRegion): string {
   568→    // Create a unique room ID based on region
   569→    const parts = [
   570→      `zoom:${region.zoomLevel}`,
   571→      `from:${region.fromDate}`,
   572→      `to:${region.toDate}`,
   573→    ];
   574→    if (region.trainIds?.length) {
   575→      parts.push(`trains:${region.trainIds.slice(0, 5).join(',')}`);
   576→    }
   577→    if (region.depotIds?.length) {
   578→      parts.push(`depots:${region.depotIds.join(',')}`);
   579→    }
   580→    return `canvas:${parts.join('|')}`;
   581→  }
   582→
   583→  // ===========================================================================
   584→  // Helper Methods
   585→  // ===========================================================================
   586→
   587→  private send(connectionId: string, message: ServerMessage): void {
   588→    const ws = this.sockets.get(connectionId);
   589→    if (ws) {
   590→      try {
   591→        ws.send(JSON.stringify(message));
   592→      } catch (error) {
   593→        this.log.error({ connectionId, error }, 'Failed to send WebSocket message');
   594→        this.cleanup(connectionId);
   595→      }
   596→    }
   597→  }
   598→
   599→  private sendError(connectionId: string, code: string, message: string, details?: unknown): void {
   600→    this.send(connectionId, {
   601→      type: 'error',
   602→      data: { code, message, details },
   603→    });
   604→  }
   605→
   606→  private disconnect(connectionId: string, reason: string): void {
   607→    const ws = this.sockets.get(connectionId);
   608→    if (ws) {
   609→      try {
   610→        ws.close(1000, reason);
   611→      } catch {
   612→        // Ignore close errors
   613→      }
   614→    }
   615→    this.cleanup(connectionId);
   616→  }
   617→
   618→  private cleanup(connectionId: string): void {
   619→    const connection = this.connections.get(connectionId);
   620→    if (connection) {
   621→      // Remove from user connections
   622→      if (connection.userId) {
   623→        const userConns = this.userConnections.get(connection.userId);
   624→        if (userConns) {
   625→          userConns.delete(connectionId);
   626→          if (userConns.size === 0) {
   627→            this.userConnections.delete(connection.userId);
   628→          }
   629→        }
   630→      }
   631→
   632→      // Leave all rooms
   633→      for (const room of this.rooms.values()) {
   634→        room.clients.delete(connectionId);
   635→      }
   636→    }
   637→
   638→    // Clear auth timeout
   639→    const timeoutHandle = this.authTimeouts.get(connectionId);
   640→    if (timeoutHandle) {
   641→      clearTimeout(timeoutHandle);
   642→      this.authTimeouts.delete(connectionId);
   643→    }
   644→
   645→    this.connections.delete(connectionId);
   646→    this.sockets.delete(connectionId);
   647→  }
   648→
   649→  private broadcastPing(): void {
   650→    for (const [connectionId, connection] of this.connections) {
   651→      if (connection.state === 'authenticated') {
   652→        this.send(connectionId, { type: 'pong' } as ServerMessage);
   653→      }
   654→    }
   655→  }
   656→
   657→  // ===========================================================================
   658→  // Statistics
   659→  // ===========================================================================
   660→
   661→  /**
   662→   * Get hub statistics for monitoring
   663→   */
   664→  getStats(): {
   665→    totalConnections: number;
   666→    authenticatedConnections: number;
   667→    uniqueUsers: number;
   668→    rooms: number;
   669→    subscriptions: number;
   670→  } {
   671→    let authenticatedCount = 0;
   672→    let totalSubscriptions = 0;
   673→
   674→    for (const connection of this.connections.values()) {
   675→      if (connection.state === 'authenticated') {
   676→        authenticatedCount++;
   677→      }
   678→      totalSubscriptions += connection.subscriptions.size;
   679→    }
   680→
   681→    return {
   682→      totalConnections: this.connections.size,
   683→      authenticatedConnections: authenticatedCount,
   684→      uniqueUsers: this.userConnections.size,
   685→      rooms: this.rooms.size,
   686→      subscriptions: totalSubscriptions,
   687→    };
   688→  }
   689→
   690→  /**
   691→   * Get connection by ID
   692→   */
   693→  getConnection(connectionId: string): ClientConnection | undefined {
   694→    return this.connections.get(connectionId);
   695→  }
   696→
   697→  /**
   698→   * Get all connections for a user
   699→   */
   700→  getUserConnections(userId: string): ClientConnection[] {
   701→    const connectionIds = this.userConnections.get(userId);
   702→    if (!connectionIds) return [];
   703→
   704→    const connections: ClientConnection[] = [];
   705→    for (const connectionId of connectionIds) {
   706→      const conn = this.connections.get(connectionId);
   707→      if (conn) {
   708→        connections.push(conn);
   709→      }
   710→    }
   711→    return connections;
   712→  }
   713→}
   714→
   715→// =============================================================================
   716→// WebSocket Data Interface (for Bun)
   717→// =============================================================================
   718→
   719→export interface WebSocketData {
   720→  connectionId: string;
   721→  ipAddress?: string;
   722→  userAgent?: string;
   723→}
   724→
   725→// =============================================================================
   726→// Singleton Instance
   727→// =============================================================================
   728→
   729→let hubInstance: WebSocketHub | null = null;
   730→
   731→/**
   732→ * Get the singleton WebSocketHub instance
   733→ */
   734→export function getWebSocketHub(): WebSocketHub {
   735→  if (!hubInstance) {
   736→    hubInstance = new WebSocketHub();
   737→  }
   738→  return hubInstance;
   739→}
   740→
   741→/**
   742→ * Create a new connection ID
   743→ */
   744→export function createConnectionId(): string {
