   351→fleetRoutes.get('/depots/:id', async (c) => {
   352→  const requestId = getRequestId(c);
   353→  const depotId = c.req.param('id');
   354→
   355→  if (!isValidUuid(depotId)) {
   356→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid depot ID format', requestId), 400);
